package com.example.myapplication.domain.usecase

import com.example.myapplication.domain.model.BodyGoldenRatioResult
import com.example.myapplication.domain.model.BodyRatioStatus
import kotlin.math.abs
import kotlin.math.sqrt

/**
 * Faza 30.1 — Clean Architecture: Poslovna logika za telesni Zlati Rez.
 * Faza 30.7 — Odstranjeni emoji-ji in hardkodirani nizi; status vrača BodyRatioStatus enum.
 *             Dodane realne biološke meje (30–250 cm) za preprečevanje popačenih rezultatov.
 *
 * KMP-ready: brez Android odvisnosti.
 */
class CalculateBodyGoldenRatioUseCase {

    private val phi = (1.0 + sqrt(5.0)) / 2.0  // ≈ 1.618

    companion object {
        /** Faza 30.7 — Biološke meje za telesne obsege */
        const val MIN_CIRCUMFERENCE_CM = 30.0
        const val MAX_CIRCUMFERENCE_CM = 250.0
    }

    operator fun invoke(
        shoulderCm: Double,
        waistCm: Double,
        hipCm: Double = 0.0,
        heightCm: Double = 0.0,
        isMale: Boolean = true
    ): BodyGoldenRatioResult {

        // Faza 30.7 — Realne biološke meje (ne zgolj > 0)
        require(shoulderCm in MIN_CIRCUMFERENCE_CM..MAX_CIRCUMFERENCE_CM) {
            "Obseg ramen mora biti med $MIN_CIRCUMFERENCE_CM in $MAX_CIRCUMFERENCE_CM cm (dobil: $shoulderCm)"
        }
        require(waistCm in MIN_CIRCUMFERENCE_CM..MAX_CIRCUMFERENCE_CM) {
            "Obseg pasu mora biti med $MIN_CIRCUMFERENCE_CM in $MAX_CIRCUMFERENCE_CM cm (dobil: $waistCm)"
        }
        require(hipCm == 0.0 || hipCm in MIN_CIRCUMFERENCE_CM..MAX_CIRCUMFERENCE_CM) {
            "Obseg bokov mora biti 0 (ni vnosu) ali med $MIN_CIRCUMFERENCE_CM in $MAX_CIRCUMFERENCE_CM cm (dobil: $hipCm)"
        }

        // ── 1. Razmerje ramen/pas (Adonis Index) ────────────────────────────
        val shoulderToWaistRatio = shoulderCm / waistCm
        val idealSWR = if (isMale) phi else 1.45
        val deviationFromPhi = abs(shoulderToWaistRatio - idealSWR) / idealSWR

        // ── 2. Razmerje pas/višina (WHtR) ────────────────────────────────────
        val waistToHeightRatio = if (heightCm > 0) waistCm / heightCm else -1.0

        // ── 3. Razmerje ramen/boki ───────────────────────────────────────────
        val shoulderToHipRatio = if (hipCm > 0) shoulderCm / hipCm else -1.0

        // ── 4. Skupni rezultat (0..1) ────────────────────────────────────────
        val swrScore = (1.0 - deviationFromPhi.coerceIn(0.0, 1.0)) * 0.60
        val whtrScore = when {
            waistToHeightRatio < 0     -> 0.25 * 0.5
            waistToHeightRatio <= 0.50 -> 0.25
            waistToHeightRatio <= 0.60 -> 0.25 * (1.0 - (waistToHeightRatio - 0.50) * 5.0)
            else                       -> 0.0
        }
        val hipScore = when {
            shoulderToHipRatio < 0                              -> 0.15 * 0.5
            isMale  && shoulderToHipRatio in 1.05..1.20         -> 0.15
            !isMale && shoulderToHipRatio in 0.90..1.10         -> 0.15
            else                                                -> 0.15 * 0.5
        }
        val overallScore = (swrScore + whtrScore + hipScore).coerceIn(0.0, 1.0)

        // ── 5. Status — Faza 30.7: enum, brez emoji/stringov v domain sloju ─
        val status: BodyRatioStatus = when {
            deviationFromPhi <= 0.03 -> BodyRatioStatus.GOLDEN_RATIO
            deviationFromPhi <= 0.08 -> BodyRatioStatus.EXCELLENT
            deviationFromPhi <= 0.15 -> BodyRatioStatus.GOOD
            deviationFromPhi <= 0.25 -> BodyRatioStatus.AVERAGE
            else                     -> BodyRatioStatus.NEEDS_WORK
        }

        return BodyGoldenRatioResult(
            shoulderToWaistRatio = shoulderToWaistRatio,
            waistToHeightRatio   = if (waistToHeightRatio < 0) 0.0 else waistToHeightRatio,
            shoulderToHipRatio   = if (shoulderToHipRatio < 0) 0.0 else shoulderToHipRatio,
            overallScore         = overallScore,
            status               = status,
            deviationFromPhi     = deviationFromPhi
        )
    }
}

package com.example.myapplication.domain.usecase

import com.example.myapplication.domain.model.NutritionTargets

/**
 * Faza 29.8 — Clean Architecture: Poslovna logika za izračun prehranskih ciljev.
 *
 * Preseljeno iz NutritionViewModel.nutritionTargets combine bloka → Domain sloj.
 * ViewModel je zdaj samo koordinator — ne vsebuje več poslovne logike.
 *
 * Stroga prioritetna hierarhija:
 *   1. frozenCalories (zamrznjeni Firestore snapshot tega dne)
 *   2. hybridTDEE > 800 (izmerjeni TDEE iz ProgressViewModel)
 *   3. planCalories > 0 (real-time plan iz Firestore)
 *   4. 2000 kcal (varni fallback)
 *
 * KMP-ready: brez Android/Firebase odvisnosti.
 */
class GetNutritionTargetsUseCase {

    operator fun invoke(
        frozenCalories: Int?,
        frozenProtein: Int?,
        frozenCarbs: Int?,
        frozenFat: Int?,
        planCalories: Int,
        planProtein: Int,
        planCarbs: Int,
        planFat: Int,
        hybridTDEE: Int
    ): NutritionTargets {

        // Kalorije — stroga prioriteta + zaokrožitev navzdol na 100
        val rawCalories = when {
            frozenCalories != null   -> frozenCalories
            hybridTDEE > 800         -> hybridTDEE
            planCalories > 0         -> planCalories
            else                     -> 2000
        }
        val calories = (rawCalories / 100) * 100

        // Makri — frozen → plan → fallback (brez !! operatorja)
        val protein = when {
            (frozenProtein ?: 0) > 0 -> frozenProtein ?: 100
            planProtein > 0          -> planProtein
            else                     -> 100
        }
        val carbs = when {
            (frozenCarbs ?: 0) > 0   -> frozenCarbs ?: 200
            planCarbs > 0            -> planCarbs
            else                     -> 200
        }
        val fat = when {
            (frozenFat ?: 0) > 0     -> frozenFat ?: 60
            planFat > 0              -> planFat
            else                     -> 60
        }

        return NutritionTargets(
            calories = calories,
            protein  = protein,
            carbs    = carbs,
            fat      = fat
        )
    }
}

package com.example.myapplication.domain.usecase

import com.example.myapplication.domain.repository.BodyMeasurementsRepository

/**
 * Faza 30.6 — Use Case za shranjevanje telesnih meritev.
 *
 * Domenska validacija:
 *   - shoulderCm in waistCm morata biti > 0 (brez njiju Golden Ratio ni smiseln)
 *   - hipCm je opcijsko (zadostuje 0.0)
 *
 * Po uspešni validaciji kliče BodyMeasurementsRepository.saveMeasurements()
 * ki izvede atomarni batch write (profil + subcollection history).
 *
 * Klic chain: VM.saveBodyMeasurements() → UseCase → Repository → Firestore
 */
class SaveBodyMeasurementsUseCase(
    private val bodyMeasurementsRepository: BodyMeasurementsRepository
) {
    suspend operator fun invoke(
        shoulderCm: Double,
        waistCm: Double,
        hipCm: Double = 0.0,
        heightCm: Double = 0.0
    ): Result<Unit> {
        // Domenska validacija — ne shranjujemo praznih vnosov
        if (shoulderCm <= 0.0) {
            return Result.failure(IllegalArgumentException("Obseg ramen mora biti večji od 0."))
        }
        if (waistCm <= 0.0) {
            return Result.failure(IllegalArgumentException("Obseg pasu mora biti večji od 0."))
        }

        return bodyMeasurementsRepository.saveMeasurements(
            shoulderCm = shoulderCm,
            waistCm    = waistCm,
            hipCm      = hipCm,
            heightCm   = heightCm
        )
    }
}

package com.example.myapplication.domain.usecase

import com.example.myapplication.domain.model.PlanResult

class SwapPlanDaysUseCase {
    /**
     * Zamenjaj dan A ↔ dan B v planu.
     *
     * @param lockedDay Opcijsko — danes opravljen dan (WORKOUT_DONE / STRETCHING_DONE).
     *                  Če je lockedDay == dayA ali dayB, swap ni dovoljen (Faza 9: Day Locking).
     *                  Preverjanje v UI sloju (PlanPathDialog) je primarna zapora;
     *                  ta parameter je varnostna plast na domenskem sloju.
     */
    fun invoke(currentPlan: PlanResult, dayA: Int, dayB: Int, lockedDay: Int? = null): Result<PlanResult> {
        return try {
            //  Faza 9: varnostna domeska zapora za zaklenjen dan
            if (lockedDay != null && (lockedDay == dayA || lockedDay == dayB)) {
                return Result.failure(Exception("Day $lockedDay is locked (already completed today). Cannot swap."))
            }

            val weekA = (dayA - 1) / 7
            val weekB = (dayB - 1) / 7

            if (weekA != weekB) {
                return Result.failure(Exception("Cross-week swap not allowed: $dayA <-> $dayB"))
            }

            val allDays = currentPlan.weeks.flatMap { it.days }.toMutableList()
            val iA = allDays.indexOfFirst { it.dayNumber == dayA }
            val iB = allDays.indexOfFirst { it.dayNumber == dayB }

            if (iA >= 0 && iB >= 0) {
                val rA = allDays[iA].isRestDay
                val fA = allDays[iA].focusLabel
                val rB = allDays[iB].isRestDay
                val fB = allDays[iB].focusLabel
                allDays[iA] = allDays[iA].copy(isRestDay = rB, focusLabel = fB)
                allDays[iB] = allDays[iB].copy(isRestDay = rA, focusLabel = fA)
            }

            val updatedWeeks = currentPlan.weeks.map { week ->
                week.copy(days = allDays.filter { (it.dayNumber - 1) / 7 == week.weekNumber - 1 })
            }
            val updatedPlan = currentPlan.copy(weeks = updatedWeeks)
            Result.success(updatedPlan)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

package com.example.myapplication.domain.usecase

import com.example.myapplication.domain.model.PlanResult
import com.example.myapplication.domain.repository.PlanRepository

/**
 * Faza 30.4 — Clean Architecture: VM → UseCase → Repository → DataStore.
 *
 * UseCase odgovornosti:
 *   1. Domenska validacija (triple lock: blank id, lockedDay, isFrozen)
 *   2. Gradnja posodobljenega lokalnega modela (za optimistični UI)
 *   3. Klic planRepository.swapDays() za persistenco (Firestore)
 *
 * ViewModel ne ve za obstoj PlanDataStore — kliče SAMO ta use case.
 */
class SwapPlanDaysUseCase(
    private val planRepository: PlanRepository
) {

    /**
     * Validira, gradi lokalni posodobljeni model in persistira v Firestore.
     *
     * @return Result.success(updatedPlan) ko je Firestore zapis uspel
     *         Result.failure(SwapValidationException) za domenske napake
     *         Result.failure(Exception) za omrežne/Firestore napake
     */
    suspend fun invoke(
        currentPlan: PlanResult,
        dayA: Int,
        dayB: Int,
        lockedDay: Int? = null
    ): Result<PlanResult> {
        // ── Domenska validacija (triple lock) ──────────────────────────────────

        //  Zapora 1: prazen plan ID — pot do načrta ni naložena
        if (currentPlan.id.isBlank()) {
            return Result.failure(
                SwapValidationException("Plan path is empty — cannot swap without a valid plan ID.")
            )
        }

        //  Zapora 2: danes opravljen dan (WORKOUT_DONE / STRETCHING_DONE)
        if (lockedDay != null && (lockedDay == dayA || lockedDay == dayB)) {
            return Result.failure(
                SwapValidationException("Day $lockedDay is locked (completed today). Cannot swap.")
            )
        }

        // Cross-week kontrola
        val weekA = (dayA - 1) / 7
        val weekB = (dayB - 1) / 7
        if (weekA != weekB) {
            return Result.failure(
                SwapValidationException(
                    "Cross-week swap not allowed: day $dayA (week ${weekA + 1}) ↔ day $dayB (week ${weekB + 1})"
                )
            )
        }

        val allDays = currentPlan.weeks.flatMap { it.days }.toMutableList()
        val iA = allDays.indexOfFirst { it.dayNumber == dayA }
        val iB = allDays.indexOfFirst { it.dayNumber == dayB }

        if (iA < 0 || iB < 0) {
            return Result.failure(
                SwapValidationException("Day not found in plan: dayA=$dayA (idx=$iA), dayB=$dayB (idx=$iB)")
            )
        }

        //  Zapora 3: isFrozen — UI preverjanje ni dovolj, domain mora blokirati
        if (allDays[iA].isFrozen) {
            return Result.failure(
                SwapValidationException("Day $dayA is frozen (completed). Cannot swap locked days.")
            )
        }
        if (allDays[iB].isFrozen) {
            return Result.failure(
                SwapValidationException("Day $dayB is frozen (completed). Cannot swap locked days.")
            )
        }

        // ── Gradnja lokalnega modela (optimistični UI) ─────────────────────────
        // Polna zamenjava vsebine dni: ohrani dayNumber, zamenjaj VSE ostale podatke
        val contentA = allDays[iA]
        val contentB = allDays[iB]
        allDays[iA] = contentB.copy(dayNumber = dayA)
        allDays[iB] = contentA.copy(dayNumber = dayB)

        val updatedWeeks = currentPlan.weeks.map { week ->
            week.copy(days = allDays.filter { (it.dayNumber - 1) / 7 == week.weekNumber - 1 })
        }
        val updatedPlan = currentPlan.copy(weeks = updatedWeeks)

        // ── Persistenca: VM → UseCase → Repository → DataStore ────────────────
        return try {
            planRepository.swapDays(currentPlan.id, dayA, dayB)
                .map { updatedPlan }  // Firestore uspel → vrni posodobljeni lokalni model
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

/**
 * Specifična izjema za domenske validacijske napake pri zamenjavi dni.
 * UI jo lahko prikaže brez stack tracea.
 */
class SwapValidationException(message: String) : Exception(message)

